def edit_file(self, filename: str) -> None:
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    popen_kwargs: dict[str, t.Any] = {}

    if self.process_priority is not None:
        if WIN:
            priority_classes = {
                "low": subprocess.IDLE_PRIORITY_CLASS,  # type: ignore
                "below_normal": subprocess.BELOW_NORMAL_PRIORITY_CLASS,  # type: ignore
                "normal": subprocess.NORMAL_PRIORITY_CLASS,  # type: ignore
                "above_normal": subprocess.ABOVE_NORMAL_PRIORITY_CLASS,  # type: ignore
                "high": subprocess.HIGH_PRIORITY_CLASS,  # type: ignore
            }
            popen_kwargs["creationflags"] = priority_classes[self.process_priority]
        else:
            nice_value = _NICE_VALUES[self.process_priority]

            def _set_priority(nice_value: int = nice_value) -> None:
                try:
                    os.nice(nice_value)
                except OSError:
                    # Not all priority levels are available to
                    # unprivileged users (e.g. negative nice values).
                    # Fall back to the default priority in that case.
                    pass

            popen_kwargs["preexec_fn"] = _set_priority

    try:
        c = subprocess.Popen(
            f'{editor} "{filename}"', env=environ, shell=True, **popen_kwargs
        )
        exit_code = c.wait()

